// Input comes from n8n as items
const input = $('Webhook').first().json.body.data; // your JSON string

let parsed;
try {
    parsed = JSON.parse(input); // parse the inner JSON
} catch (e) {
    console.error("Invalid JSON:", e.message);
    parsed = {};
}

// n8n requires an array of objects
return [
    {
        json: parsed
    }
];
